var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"얼마 뒤","JPN":"しばらくして","ENG":"A few days later","TWN":"不久後","SCN":"不久后","DEU":"A few days later","FRA":"A few days later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 가변 심도 좌표\\n<color=#ff3636>필하모닉 홀</color>","JPN":"裏世界可変深度座標\\n<color=#ff3636>フィルハーモニーホール</color>","ENG":"[[","TWN":"異界可變深度座標\\n<color=#ff3636>管弦樂廳</color>","SCN":"异界可变深度坐标\\n<color=#ff3636>交响乐厅</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"야크샤 전대 및 연합 전대.\\n강습 작전 수행 중.\\n작전명 <color=#ffd34c>커튼콜</color>","JPN":"ヤクシャー戦隊および連合戦隊。\\n強襲作戦遂行中。\\n作戦名<color=#ffd34c>カーテンコール</color>","ENG":"[[","TWN":"夜叉戰隊與聯合戰隊。\\n強襲作戰執行中。\\n作戰代號：<color=#ffd34c>謝幕</color>","SCN":"夜叉战队与联合战队。\\n强袭作战执行中。\\n作战代号：<color=#ffd34c>谢幕</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"모네카! 함 내 기갑병력의 화력 투사를 최대로! 강하 포인트를 확보한다!","JPN":"モネカ！　艦内機甲兵力の火力を最大限まで上げて！　強化ポイントを確保する！","ENG":"Moneka! Maximize the firepower projection of all the armored units! Secure the drop point!","TWN":"莫奈卡！最大化艦艇裝甲部隊的火力投射！確保著陸點！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"지원을 약속한 다른 전대는 얼마나 도착했지?","JPN":"支援を約束した他戦隊は？","ENG":"How many divisions that were supposed to provide support have arrived?","TWN":"承諾支援的其他戰隊來了多少？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"현재 야크샤, 아르콘 전대가 가변 심도 다이브에 성공하였습니다!","JPN":"現在、ヤクシャー、アルコン戦隊が可変深度ダイブに成功しました！","ENG":"Currently, Yaksha and Arkon Division have successfully dived into the variable depths!","TWN":"目前，夜叉和阿勒坤戰隊已成功躍入可變深度！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이어서 다음 좌표가 갱신되면, 지원 병력을 보낸 카멜롯과 카르데나스 외 2개 전대가…….","JPN":"次の座標更新後、支援兵力を送ったキャメロットとカルデナスの他2戦隊が……","ENG":"When the next coordinates are updated, Camelot, Cardenas, and two other divisions who sent support troops will...","TWN":"再下一個座標更新時，派出援軍的卡梅羅和卡特納斯，以及另外兩個戰隊…… 。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어라……? 병기개발국에서도 지원을 보내왔습니다……!","JPN":"え……？　兵器開発局からも支援が届きました……！","ENG":"Huh...? The Weapon Development Bureau also sent support...!","TWN":"嗯……？兵器開發局也派遣了支援……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>다 쓸어 버리는 불사신 괴물</color>……? 이게 뭐죠……?","JPN":"<color=#ffd34c>万物をなぎ払う不死身の怪物</color>……？　これは何でしょう……？","ENG":"<color=#ffd34c>Immortal monster of total destruction</color>...? What is this...?","TWN":"<color=#ffd34c>橫掃一切的不死怪物</color>……？那是什麼……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 쥐스틴이 개발국장에게 부탁한 모양이네.","JPN":"ふふ、ジュスティーヌが開発局長に頼んでくれたみたいね。","ENG":"Fu fuu. I assume Justine asked the chief of development a favor.","TWN":"呵呵，看來是潔絲婷向開發局求助了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하여간 쪼그매도 믿음직스럽다니까~","JPN":"小さいのに本当、頼もしい子なんだから。","ENG":"I always knew I could count on that little one.","TWN":"那個小鬼還是值得信賴的～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"작전 구역의 전 연합 전대원!","JPN":"作戦区域の全連合戦隊員の皆さん！","ENG":"All coalition members in the operation zone!","TWN":"作戰區域的全體聯合戰隊員！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이번 작전에서 선두를 맡게 된 제4수색전대 야크샤의 주디 스위프트입니다.","JPN":"今回の作戦で先頭に立つことになった第4捜索戦隊ヤクシャーのジュディ・スウィフトです。","ENG":"I am Judy Swift of the 4th Recon Division Yaksha, who will be taking the lead on this operation.","TWN":"我是第4偵察戰隊夜叉的茱蒂·斯威福特，將負責此次的作戰。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"브리핑에서 말씀드렸다시피, 이번 강습작전은 속전속결이 가장 중요합니다.","JPN":"ブリーフィングでもお伝えした通り、今回の強襲作戦では速戦即決が成功の要になります。","ENG":"As I said in the briefing, the most important aspect of this entire assault operation is speed.","TWN":"正如我在簡報中所說，本次強襲作戰最重要的是速戰速決。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다른 전대가 현실에 부상중인 마에스트로의 발을 묶고 있는 사이…….","JPN":"他の戦隊が現実に浮上しているマエストロの足を引き留めている間……","ENG":"While the other divisions are slowing down Maestra who will be emerging in the Normalside...","TWN":"當其他戰隊在現世中阻攔躍出的指揮家時……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"저희는 이곳 필하모닉 홀을 공략. 엘리시움의 시설과 최고 단원들을 전부 격파합니다.","JPN":"私たちはここフィルハーモニーホールを攻略。エリシウムの施設および首席奏者全員を撃破します。","ENG":"we will attack Philharmonic Hall, and all of Elysium's facilities and Elite Members.","TWN":"我們的目標是攻佔這裡的管弦樂廳。破壞樂團的所有設施，剿滅她們的樂手。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 후, 악단을 잃어 전력이 약화된 마에스트로까지 공략을 시도합니다.","JPN":"その後、楽団を失い戦力が弱化したマエストロの攻略に力を集結します。","ENG":"Afterward, we will attempt a strike on Maestra, who will be weakened after losing her Orchestra.","TWN":"之後，再嘗試殲滅失去了樂團，實力被削弱的指揮家。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"부디, 이 작전으로 가증스러운 오케스트라 연주에 막을 내릴 수 있기를 기도하며.","JPN":"どうかこの作戦で、あの忌々しいオーケストラの幕を下ろすことができるように。","ENG":"I pray that with this operation being successful, we can finally put an end to the abominable orchestra performance.","TWN":"請祈禱，本次作戰能夠結束管弦樂隊的惡劣表演。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 야크샤 전대가 가장 앞장서 연합 전대를 이끌겠습니다!","JPN":"私たちヤクシャー戦隊が先陣を切り、連合戦隊を導いてみせます！","ENG":"We, the Yaksha Division, will take the lead of the coalition divisions!","TWN":"我們夜叉戰隊將在最前方帶領聯合戰隊！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"말도 안 돼!","JPN":"あり得ないわ！","ENG":"This cannot be!","TWN":"不可能！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관리국 녀석들이 어떻게 가변 심도에 있는 이곳을……!!","JPN":"どうして管理局のやつらが、可変深度にあるこの場所を突き止めた……！？","ENG":"How did the Administration manage to enter the variable depths...?!","TWN":"管理局那些傢伙，是怎麼來到可變深度的……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"설마, 벌써 이곳에 다다를 수 있는 기술력을 손에 넣은 건가?","JPN":"まさか、もうここに辿り着ける技術力を手に入れたっていうの？","ENG":"Have they... already obtained the technology to reach this place?","TWN":"難道，他們已經掌握了可以達到這裡的技術了嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};